#include <stdio.h>
#include <stdlib.h>

// Initialize weights and bias
float w = 0.0;
float b = 0.0;

// Define learning rate and number of epochs
float learning_rate = 0.01;
int epochs = 1000;

// Define the linear regression function
void linear_regression(float X[], float y[], int n) {
 for (int i = 0; i < epochs; i++) {
 float predictions[n];
 float errors[n];
 for (int j = 0; j < n; j++) {
 predictions[j] = w * X[j] + b;
 errors[j] = predictions[j] - y[j];
 }
 w -= learning_rate * errors[0];
 b -= learning_rate * errors[0];
 }
}
